import { describe, test, expect, beforeEach } from 'bun:test';
import { GnosisEngine } from '../runtime/engine.js';
import { GnosisRegistry } from '../runtime/registry.js';
import { BettyCompiler } from '../betty/compiler.js';

describe('GnosisEngine', () => {
    let registry: GnosisRegistry;
    let engine: GnosisEngine;
    let compiler: BettyCompiler;

    beforeEach(() => {
        registry = new GnosisRegistry();
        engine = new GnosisEngine(registry);
        compiler = new BettyCompiler();
    });

    test('returns message for empty graph', async () => {
        const result = await engine.execute({ nodes: new Map(), edges: [] });
        expect(result).toContain('No graph to execute');
    });

    test('executes single sequential node', async () => {
        registry.register('Source', async (payload, props) => {
            return [1, 2, 3];
        });

        const { ast } = compiler.parse(`
            (input: Source { data: '[1,2,3]' })
            (input)-[:PROCESS]->(output)
        `);

        const result = await engine.execute(ast!);
        expect(result).toContain('Executing [input]');
        expect(result).toContain('Final System Result');
    });

    test('executes sequential chain', async () => {
        const order: string[] = [];

        registry.register('Step1', async (payload) => {
            order.push('step1');
            return 'from-step1';
        });
        registry.register('Step2', async (payload) => {
            order.push('step2');
            return `${payload}-step2`;
        });

        const { ast } = compiler.parse(`
            (a: Step1)
            (b: Step2)
            (a)-[:PROCESS]->(b)-[:PROCESS]->(c)
        `);

        const result = await engine.execute(ast!);
        expect(order).toEqual(['step1', 'step2']);
        expect(result).toContain('from-step1-step2');
    });

    test('executes FORK + FOLD topology', async () => {
        registry.register('Source', async () => [10, 20]);
        registry.register('Double', async (payload) => (payload as number[]).map(x => x * 2));
        registry.register('Triple', async (payload) => (payload as number[]).map(x => x * 3));

        const { ast } = compiler.parse(`
            (input: Source)
            (dbl: Double)
            (trp: Triple)
            (input)-[:FORK]->(dbl | trp)
            (dbl | trp)-[:FOLD { strategy: 'merge-all' }]->(result)
            (result)-[:PROCESS]->(output)
        `);

        const result = await engine.execute(ast!);
        expect(result).toContain('FORK');
        expect(result).toContain('Fold');
        expect(result).toContain('Final System Result');
    });

    test('executes FORK + RACE topology', async () => {
        registry.register('Fast', async () => {
            return { path: 'fast', value: 'winner', time: 1 };
        });
        registry.register('Slow', async () => {
            await new Promise(r => setTimeout(r, 50));
            return { path: 'slow', value: 'loser', time: 50 };
        });

        const { ast } = compiler.parse(`
            (fast: Fast)
            (slow: Slow)
            (a)-[:FORK]->(fast | slow)
            (fast | slow)-[:RACE]->(winner)
        `);

        const result = await engine.execute(ast!);
        expect(result).toContain('FORK');
        expect(result).toContain('Rac');
    });

    test('skips nodes without handlers', async () => {
        const { ast } = compiler.parse(`
            (a)-[:PROCESS]->(b)-[:PROCESS]->(c)
        `);

        const result = await engine.execute(ast!);
        expect(result).toContain('No handler');
    });

    test('detects cycles and breaks', async () => {
        // Manually construct a cyclic graph since the parser doesn't prevent it
        const ast = {
            nodes: new Map([
                ['a', { id: 'a', labels: [], properties: {} }],
                ['b', { id: 'b', labels: [], properties: {} }],
            ]),
            edges: [
                { sourceIds: ['a'], targetIds: ['b'], type: 'PROCESS', properties: {} },
                { sourceIds: ['b'], targetIds: ['a'], type: 'PROCESS', properties: {} },
            ]
        };

        const result = await engine.execute(ast);
        expect(result).toContain('Cycle detected');
    });

    test('handles node not found in AST gracefully', async () => {
        const ast = {
            nodes: new Map([
                ['a', { id: 'a', labels: [], properties: {} }],
            ]),
            edges: [
                { sourceIds: ['a'], targetIds: ['missing'], type: 'PROCESS', properties: {} },
            ]
        };

        const result = await engine.execute(ast);
        expect(result).toContain('not found in AST');
    });

    test('terminates at node with no outgoing edge', async () => {
        registry.register('Leaf', async () => 'done');

        const { ast } = compiler.parse(`
            (a: Leaf)-[:PROCESS]->(b)
        `);

        const result = await engine.execute(ast!);
        expect(result).toContain('Final node');
    });

    test('passes initial payload through chain', async () => {
        let received: any;
        registry.register('Capture', async (payload) => {
            received = payload;
            return payload;
        });

        const { ast } = compiler.parse(`
            (a: Capture)-[:PROCESS]->(b)
        `);

        await engine.execute(ast!, 'INIT_DATA');
        expect(received).toBe('INIT_DATA');
    });
});
